            ContentJson = """{"appRoute":"/display/shop-floor","startButtonLabel":"Tour Shop Floor","steps":[{"element":".sf-header","popover":{"title":"Shop Floor Header","description":"The header holds a search box, buttons to make the text bigger or smaller, a light/dark switch, and a live clock. Your text-size and theme choices are remembered, even after the browser restarts. To leave the kiosk, use Exit kiosk in the top corner.","side":"bottom"}},{"element":".sf-header__stats","popover":{"title":"Status Summary","description":"See at a glance how many workers are working (green) and on break (yellow), plus unassigned jobs, jobs done today, and any alerts (red, shown only when there are some). These update on their own every few seconds.","side":"bottom"}},{"element":".sf-grid","popover":{"title":"Worker Cards","description":"Everyone shows up as a card. A colored edge tells you their status at a glance: green for working, yellow for break, gray for clocked out. Each card shows their name, status, time so far, and up to 4 jobs. Tap a card to sign in and use the clock. You can also drag an unassigned job onto a card to assign it.","side":"top"}},{"element":".sf-card","popover":{"title":"Worker Card","description":"One person's card. The colored edge matches their clock status. Up top you see their initials, name, current status, and how long they've been in it. Below that are their jobs, each with a colored dot for its stage and a timer mark when the clock is running.","side":"right"}},{"element":".sf-action-bar","popover":{"title":"Scan Bar","description":"The bottom bar is ready for a scan and shows what was read — for example 'Job 1055 — Precision Shaft Assembly' or 'Scan not recognized'. The message clears itself after a few seconds.","side":"top"}}]}"""
