            ContentJson = """{"title":"Shop Floor Field Reference","groups":[{"heading":"Signing In","items":[{"label":"Scan + PIN","value":"Scan your badge or barcode. When it recognizes you, a PIN box appears — type your number PIN (at least 4 digits) and submit. The action screen opens."},{"label":"Tap card + password","value":"Tap your name card on the grid. A password box appears — type your full password (not your PIN) and submit. The action screen opens."},{"label":"PIN box (after a scan)","value":"A number box, hidden as you type, that takes 4 to 8 digits. It reads 'Enter your PIN' and is ready for typing right away."},{"label":"Password box (after a tap)","value":"A text box, hidden as you type. It reads 'Enter your password'."},{"label":"Submit button","value":"Turns on once you've typed something. It shows 'Verifying...' while it checks you, then opens your actions."},{"label":"Cancel button","value":"Takes you back to the main screen without signing in."},{"label":"Error messages","value":"'Invalid badge or PIN' if a scan sign-in fails, 'Invalid password' if a tap sign-in fails, and a reminder if your PIN is too short."}]},{"heading":"Automatic Timeouts","items":[{"label":"PIN box","value":"If you don't type your PIN within about 20 seconds, the box closes on its own and you're back at the main screen."},{"label":"Job picker","value":"If you don't pick a job or skip within about 15 seconds, the picker closes and signs you out."},{"label":"Action screen","value":"After about 30 seconds without a tap, you're signed out automatically. Any button press starts the timer over."},{"label":"Screen refresh","value":"Worker status, jobs, and upcoming events update on their own every few seconds."},{"label":"Clock","value":"The header clock and each worker's time so far tick up every second."},{"label":"Scan message","value":"The message in the bottom bar clears after a few seconds."},{"label":"Success message","value":"After a clock action goes through, a quick confirmation shows before you're signed out."}]},{"heading":"What's on a Worker Card","items":[{"label":"Colored edge","value":"The stripe down the left tells you the person's status at a glance: green for working, yellow for break or lunch, gray for clocked out."},{"label":"Initials","value":"A colored badge with the person's initials."},{"label":"Name","value":"The worker's full name."},{"label":"Status","value":"A short word for what they're doing right now, shown next to their name."},{"label":"Time so far","value":"How long they've been in their current status, counting up every second."},{"label":"Their jobs (up to 4)","value":"Each job shows a colored dot for its stage, the job number and title, and a timer mark when its clock is running. Overdue jobs stand out."},{"label":"More jobs","value":"A '+N more' note appears when someone has more than 4 jobs."},{"label":"Drop highlight","value":"The card lights up when you drag an unassigned job over it."},{"label":"Action feedback","value":"A green flash means an action worked; a red flash means it didn't."}]},{"heading":"Status Summary","items":[{"label":"Working","value":"How many people are currently working (shown in green)."},{"label":"On break","value":"How many people are on break or lunch (shown in yellow)."},{"label":"Unassigned","value":"How many active jobs have nobody assigned yet."},{"label":"Done today","value":"How many jobs have been finished today."},{"label":"Alerts","value":"How many maintenance alerts are open. Only shows when there are some (in red)."}]},{"heading":"Job Buttons (Action Screen)","items":[{"label":"Start Timer","value":"Begins tracking your time on the chosen job. It's off while another action is running."},{"label":"Stop Timer","value":"Stops the running timer. Only shows on a job whose clock is running."},{"label":"Mark Complete","value":"Marks the job done and moves it to the next stage. You're signed out a moment later."}]},{"heading":"Clock Buttons (Action Screen)","items":[{"label":"Which buttons show","value":"The buttons change based on what you're doing now, each with its own icon and color. Your site can add custom ones."},{"label":"Clock In","value":"Shows when you're clocked out. Puts you into working status. If you have no jobs yet, the job picker opens."},{"label":"Clock Out","value":"Shows when you're clocked in. Puts you into clocked-out status."},{"label":"Break / Lunch","value":"Shows when you're clocked in. Puts you into break or lunch status."},{"label":"While it works","value":"All buttons pause while an action runs. The one you tapped spins until it's done."}]},{"heading":"Dock Actions (by role)","items":[{"label":"Receive Goods","value":"Opens the receiving screen. Available to Admins, Managers, Office Managers, Engineers, and Production Workers. Shows only while you're clocked in."},{"label":"Ship Goods","value":"Opens the shipping screen. Available to Admins, Managers, and Office Managers. Shows only while you're clocked in."},{"label":"Receiving — pick a PO","value":"Lists open purchase orders that still have goods to receive. Each shows its number, the vendor, and how many lines it has."},{"label":"Receiving — confirm the lines","value":"Set how much to receive on each line with the plus/minus buttons. Each line shows the part, its description, and how much is still due. You can pick a bin to put it in."},{"label":"Receiving — Receive All","value":"Sends every line you set above zero. You're signed out a moment after it goes through."},{"label":"Shipping — pick a shipment","value":"Lists shipments that are pending or packed. Each shows its number, the customer, the sales order, and its status."},{"label":"Shipping — shipment details","value":"Shows the shipment number, customer, sales order, carrier, tracking number, and the items with their descriptions and quantities."},{"label":"Print Packing Slip","value":"Opens the packing slip in a new tab, ready to print."},{"label":"Mark Shipped","value":"Confirms the shipment. You're signed out a moment after it goes through."}]},{"heading":"Kiosk Settings (Header)","items":[{"label":"Smaller text","value":"Makes the text one step smaller. There are five sizes; this turns off at the smallest. Your choice is remembered."},{"label":"Current size","value":"Shows the text size you're on now."},{"label":"Bigger text","value":"Makes the text one step bigger. Turns off at the largest size."},{"label":"Light/dark switch","value":"Switches between light and dark. The icon shows which one you'll get. Your choice is remembered."},{"label":"Clock","value":"Shows the current time, ticking every second."}]},{"heading":"Which Stages Show Here","items":[{"label":"Shop-floor stages","value":"Each stage can be marked to show on the shop floor. Only marked stages put their jobs here."},{"label":"Why","value":"It keeps office-only stages like quoting, invoicing, and payment off the floor, so workers see only hands-on work."},{"label":"How to set it","value":"Set it per stage under Admin, Track Types. You can turn each stage on or off for the shop floor on its own."}]},{"heading":"Job Picker","items":[{"label":"When it opens","value":"It pops up on its own right after you clock in if you don't have any jobs yet."},{"label":"The list","value":"Shows every unassigned job with a colored stage dot, its number, title, stage, and priority. Tap one to pick it."},{"label":"Picking a job","value":"Tapping a job assigns it to you. You're signed out a moment later."},{"label":"Skip","value":"Skips picking a job and signs you out."},{"label":"Nothing to pick","value":"Shows 'No unassigned jobs available' when there are none."}]},{"heading":"Drag a Job onto a Worker","items":[{"label":"What you drag","value":"An unassigned job card from the unassigned section. Each has a grab handle."},{"label":"Where you drop it","value":"Onto any worker card in the grid. The card lights up as you drag over it."},{"label":"The result","value":"Dropping the job assigns it to that worker, and the screen refreshes."},{"label":"Good to know","value":"You can do this straight from the main screen without signing in."}]},{"heading":"What a Scan Does","items":[{"label":"Badge scan","value":"Recognizes you and opens the PIN box to sign in."},{"label":"Other scans","value":"A job barcode shows a note in the bottom bar; a storage-bin barcode opens a list of what's in that bin; anything it can't read shows 'Scan not recognized'."},{"label":"Bin scan","value":"Scanning a storage-bin barcode opens a Location view listing everything in that bin — each row shows the item, its lot number if it has one, and the quantity, with a Scan button to work on that item."},{"label":"If it can't tell","value":"If the system can't identify a scan, it treats it as a badge and opens the PIN box."},{"label":"When it listens","value":"The shop floor reads scans only on the main screen — it ignores them while a screen or box is open."}]},{"heading":"Undo a Recent Scan","items":[{"label":"Where","value":"The Recent Scan Actions panel, opened from the main shop floor screen. It lists scans from the last 6 hours."},{"label":"How far back","value":"6 hours. Only scans from the last 6 hours can be undone; older ones drop off this list but stay in the Daily Scan Log."},{"label":"Each row","value":"Shows the time, who did it, the action, the quantity, the part, where it moved from and to, and any related job, PO, or shipment."},{"label":"Reverse button","value":"Each scan that hasn't been undone has a Reverse button. Ones already undone show a 'Reversed' label and can't be undone again."},{"label":"PIN required","value":"Reverse asks for a PIN first — this is a checked correction, not a free undo. A wrong PIN shows 'Failed to reverse action. Check your PIN.'"},{"label":"What it does","value":"A good PIN undoes the movement (a move goes back to where it came from), shows a confirmation, and refreshes the list."},{"label":"Today's count","value":"The panel heading shows how many scans happened today."}]},{"heading":"Daily Scan Log","items":[{"label":"Where","value":"Open it from its own page or as a panel on the main screen."},{"label":"What it's for","value":"A read-only, filterable record of every scan for a chosen day — the full history behind the 6-hour undo panel."},{"label":"Pick a date","value":"A date picker, set to today. Choose any date to see that day."},{"label":"Filter by action","value":"Show all, or just moves, counts, receives, ships, or issues."},{"label":"Summary","value":"Shows the day's total plus a breakdown, like '4 moves, 2 receives, 1 issue'."},{"label":"Columns","value":"Time, action, part, quantity, from, to, related item, and status. Undone scans show a red 'Reversed' tag."},{"label":"Nothing to show","value":"Shows 'No scan activity for this date' when the filters find nothing."}]}]}"""
