            ContentJson = """{"appRoute":"/display/shop-floor/scan","startButtonLabel":"Tour the Scan Station","steps":[{"element":".inv-scan__header","popover":{"title":"Scan Station Header","description":"This is the Inventory Scan page. The header shows the title and a running 'Scanned' count of how many parts you've looked up this session.","side":"bottom"},"side":"bottom"},{"element":".inv-scan__cta","popover":{"title":"Scan to Begin","description":"The big prompt means the page is waiting for you. Just scan a part barcode — or a bin or job barcode — to start. What you scan decides which actions you're offered.","side":"bottom"},"side":"bottom"},{"element":".inv-scan__input-area","popover":{"title":"Scan Box","description":"This box stays ready, so a handheld scanner lands right here on its own. You can also type a part number and press Enter. When the part is found, a screen opens with the actions you can take, such as Move, Count, Receive, and Ship.","side":"top"},"side":"top"},{"element":".inv-scan__input-area","popover":{"title":"Multi-Scan for Repeat Work","description":"Turn on Multi-Scan to keep the screen open after each action, so you can scan the next part right away — handy for receiving a pallet or moving a whole shelf. With it off, the screen closes after each action and brings you back here.","side":"top"},"side":"top"},{"element":".inv-scan__body","popover":{"title":"Recent Scans","description":"As you go, a Recent Scans list builds up here with each part's number, description, and current stock — a quick record of what you've worked through this session.","side":"top"},"side":"top"}]}"""
